// ─── AUTH CHECK ─────────────────────────────────────────────────────────────
requireAuth();

// ── AUTO-LOAD LAST UPLOAD FROM SUPABASE ────────────────────────
(async function autoLoadLastUpload(){
  try {
    const upload = await getLastUpload();
    if(!upload) return; // No previous uploads, user needs to upload first
    // Only auto-load if no data currently loaded
    if(typeof G !== 'undefined' && G && G.total > 0) return;

    const [cities, carriers] = await Promise.all([
      getUploadCities(upload.id),
      getUploadCarriers(upload.id)
    ]);

    if(!cities.length && !carriers.length) return;

    // Populate global stats
    G = {
      total: upload.total_orders || 0,
      entregados: upload.delivered || 0,
      devoluciones: upload.returned || 0,
      tasa_entrega: parseFloat(upload.delivery_rate) || 0,
      ciudades: upload.cities_count || cities.length,
      transportadoras: upload.carriers_count || carriers.length
    };

    // Populate cities array
    C = cities.map(function(c){
      var breakdown = [];
      if(c.carrier_breakdown && typeof c.carrier_breakdown === 'object'){
        Object.entries(c.carrier_breakdown).forEach(function(entry){
          breakdown.push([entry[0], entry[1].count||0, entry[1].delivered||0, entry[1].rate||0]);
        });
      }
      return [
        c.city,
        c.total || 0,
        c.delivered || 0,
        c.returned || 0,
        parseFloat(c.rate) || 0,
        c.best_carrier ? [c.best_carrier] : null,
        breakdown
      ];
    });

    // Populate carriers array
    T = carriers.map(function(c){
      return {
        transportadora: c.carrier,
        total: c.total || 0,
        entregados: c.delivered || 0,
        devoluciones: c.returned || 0,
        tasa_entrega: parseFloat(c.rate) || 0
      };
    });

    // Render dashboard
    if(typeof popSelects === 'function') popSelects();
    if(typeof rMetrics === 'function') rMetrics();
    if(typeof rSem === 'function') rSem();
    if(typeof rCiu === 'function') rCiu();
    if(typeof rAlertas === 'function') rAlertas();
    if(typeof rBloq === 'function') rBloq();

    console.log('✅ Last upload auto-loaded from Supabase:', upload.id);
  } catch(e){ console.warn('Auto-load failed (ok for first use):', e); }
})();

// ─── AI API PROXY HELPER ────────────────────────────────────────────────────
async function _getAuthToken(){
  const s = await getSession();
  if(!s || !s.access_token) throw new Error('Sesion expirada. Recarga la pagina o inicia sesion de nuevo.');
  return s.access_token;
}

async function callAIProxy(model, prompt, maxTokens){
  const token = await _getAuthToken();
  const ctrl = new AbortController();
  const timer = setTimeout(()=>ctrl.abort(), 20000);
  try{
    const r = await fetch('/api/ai', {
      method:'POST',
      headers:{'Content-Type':'application/json','Authorization':'Bearer '+token},
      body:JSON.stringify({model, prompt, max_tokens: maxTokens||1200}),
      signal: ctrl.signal
    });
    clearTimeout(timer);
    if(r.status===401) throw new Error('Sesion expirada. Recarga la pagina.');
    if(!r.ok){
      const d = await r.json().catch(()=>({}));
      throw new Error(d.error || 'Error del servidor ('+r.status+'). Las API keys se configuran en Vercel > Settings > Environment Variables.');
    }
    const d = await r.json();
    if(d.error) throw new Error(d.error);
    return d.text;
  }catch(e){
    clearTimeout(timer);
    if(e.name==='AbortError') throw new Error('Timeout: la IA tardo mas de 20 segundos. Intenta de nuevo.');
    throw e;
  }
}

async function callChatProxy(model, messages, system, maxTokens){
  const token = await _getAuthToken();
  const ctrl = new AbortController();
  const timer = setTimeout(()=>ctrl.abort(), 20000);
  try{
    const r = await fetch('/api/chat', {
      method:'POST',
      headers:{'Content-Type':'application/json','Authorization':'Bearer '+token},
      body:JSON.stringify({model, messages, system, max_tokens: maxTokens||700}),
      signal: ctrl.signal
    });
    clearTimeout(timer);
    if(r.status===401) throw new Error('Sesion expirada. Recarga la pagina.');
    if(!r.ok){
      const d = await r.json().catch(()=>({}));
      throw new Error(d.error || 'Error del servidor ('+r.status+'). Verifica las API keys en Vercel.');
    }
    const d = await r.json();
    if(d.error) throw new Error(d.error);
    return d.text;
  }catch(e){
    clearTimeout(timer);
    if(e.name==='AbortError') throw new Error('Timeout: la IA tardo mas de 20 segundos. Intenta de nuevo.');
    throw e;
  }
}

