// ─── HELPERS ────────────────────────────────────────────────────────────────
function si(t){if(t>=80.5)return{c:'pv',l:'Verde',x:'#00ff88'};if(t>=70)return{c:'pa',l:'Amarillo',x:'#FFBE0B'};return{c:'pr',l:'Rojo',x:'#FF4757'};}
function bar(p,x){return`<div class="bar"><div class="btr"><div class="bfl" style="width:${p}%;background:${x};box-shadow:0 0 4px ${x}44"></div></div><span class="bpc">${p}%</span></div>`;}
function pill(t){const s=si(t);return`<span class="pill ${s.c}"><span class="pd" style="background:${s.x}"></span>${s.l}</span>`;}
function fn(n){return Number(n).toLocaleString('es-CO');}
function rp(id,pg,pages,cb,tot){
  const el=document.getElementById(id);if(!el)return;
  if(pages<=1){el.innerHTML='';return;}
  el.innerHTML=`<button onclick="${cb}(${pg-1})" ${pg<=1?'disabled':''}>← Anterior</button><span class="text-t3">${pg} / ${pages} · ${fn(tot)}</span><button onclick="${cb}(${pg+1})" ${pg>=pages?'disabled':''}>Siguiente →</button>`;
}
function buildC(ft){
  const m={};
  C.forEach(c=>{
    if(ft&&!c[6].some(r=>r[0]===ft))return;
    if(!m[c[0]])m[c[0]]={n:c[0],t:0,e:0,d:0};
    if(ft){const r=c[6].find(r=>r[0]===ft);if(r){m[c[0]].t+=r[1];m[c[0]].e+=r[2];m[c[0]].d+=r[1]-r[2];}}
    else{m[c[0]].t+=c[1];m[c[0]].e+=c[2];m[c[0]].d+=c[3];}
  });
  return Object.values(m).filter(x=>x.t>0).map(x=>({...x,te:Math.round(x.e/x.t*1000)/10}));
}
function getTrans(){return[...new Set(C.flatMap(c=>c[6].map(r=>r[0])))].sort();}
function popSelects(){
  const list=getTrans();
  ['ss-t','cc-t','bl-trans'].forEach(id=>{
    const el=document.getElementById(id);if(!el)return;
    el.innerHTML='<option value="">Todas las transportadoras</option>'+list.map(t=>`<option>${t}</option>`).join('');
  });
  const rc=document.getElementById('rc-c');
  if(rc)rc.innerHTML='<option value="">— Seleccionar —</option>'+C.filter(c=>c[1]>=20&&c[4]<80).sort((a,b)=>b[1]-a[1]).map(c=>`<option value="${c[0]}">${c[0]} (${c[1]} ped · ${c[4]}%)</option>`).join('');
  const ac=document.getElementById('as-c');
  if(ac)ac.innerHTML='<option value="">— Seleccionar —</option>'+C.filter(c=>c[1]>=20).sort((a,b)=>b[1]-a[1]).map(c=>`<option value="${c[0]}">${c[0]} (${c[1]} ped)</option>`).join('');
}

// ─── METRICS ────────────────────────────────────────────────────────────────
function rMetrics(){
  const tarifa = getCostosDev ? getCostosDev() : (parseInt(document.getElementById('tarifa')?.value)||18000);
  const moneda = getMoneda ? getMoneda() : 'COP';
  document.getElementById('m-tot').textContent=fn(G.total);
  document.getElementById('m-ent').textContent=fn(G.entregados);
  document.getElementById('m-es').textContent=G.tasa_entrega+'% tasa entrega';
  document.getElementById('m-dev').textContent=fn(G.devoluciones);
  document.getElementById('m-ds').textContent=(100-G.tasa_entrega).toFixed(1)+'% devolución';
  document.getElementById('m-costo').textContent='$'+fn(Math.round(G.devoluciones*tarifa/1000))+'K';
  document.getElementById('m-cs').textContent='@ $'+fn(tarifa)+' '+moneda+'/envío · '+PAISES[PAIS_ACTIVO].flag;
  document.getElementById('pbdg').textContent='MAY 25 – ENE 26 · 4 países';
  const nc=A.filter(a=>a[0]===0).length;
  if(nc>0){const ab=document.getElementById('abadge');ab.textContent=nc+' CRÍTICAS';ab.style.display='flex';}
}

