// ═══════════════════════════════════════════════════════════
// SISTEMA MULTI-PAÍS + MULTI-ARCHIVO
// Cada país tiene: nombre, moneda, costo_dev, costo_flete,
// semaforo_verde, semaforo_amarillo, datos propios
// ═══════════════════════════════════════════════════════════

const PAISES = {
  CO: { nombre:'COLOMBIA',  moneda:'COP', flag:'CO', costo_dev:18000, costo_flete:9000,  verde:80.5, amarillo:70 },
  CL: { nombre:'CHILE',     moneda:'CLP', flag:'CL', costo_dev:3500,  costo_flete:2500,  verde:85,   amarillo:75 },
  GT: { nombre:'GUATEMALA', moneda:'GTQ', flag:'GT', costo_dev:45,    costo_flete:30,    verde:80,   amarillo:70 },
  MX: { nombre:'MÉXICO',    moneda:'MXN', flag:'MX', costo_dev:95,    costo_flete:70,    verde:82,   amarillo:72 },
};

// Estado por país — cada país guarda sus propios datos
const PAIS_DATA = { CO:{C:[],T:[],G:null,A:[],P:[]}, CL:{C:[],T:[],G:null,A:[],P:[]}, GT:{C:[],T:[],G:null,A:[],P:[]}, MX:{C:[],T:[],G:null,A:[],P:[]} };
let PAIS_ACTIVO = 'CO';

// Inicializar país activo con los datos pre-cargados
(function initPaisData(){
  PAIS_DATA.CO.C = typeof C !== 'undefined' ? [...C] : [];
  PAIS_DATA.CO.T = typeof T !== 'undefined' ? [...T] : [];
  PAIS_DATA.CO.G = typeof G !== 'undefined' ? {...G} : null;
  PAIS_DATA.CO.A = typeof A !== 'undefined' ? [...A] : [];
  PAIS_DATA.CO.P = typeof P !== 'undefined' ? [...P] : [];
})();

function setPais(codigo){
  // Guardar datos actuales del país anterior
  PAIS_DATA[PAIS_ACTIVO].C = [...C]; PAIS_DATA[PAIS_ACTIVO].T = [...T];
  PAIS_DATA[PAIS_ACTIVO].G = G ? {...G} : null;
  PAIS_DATA[PAIS_ACTIVO].A = [...A]; PAIS_DATA[PAIS_ACTIVO].P = [...P];

  PAIS_ACTIVO = codigo;
  const cfg = PAISES[codigo];

  // ── Botones de país ──────────────────────────────────
  document.querySelectorAll('.pais-btn').forEach(b => {
    b.classList.remove('active');
    const lbl = b.querySelector('.pais-btn-label');
    if(lbl) lbl.style.display = 'none';
  });
  const btn = document.getElementById('pb-'+codigo);
  if(btn){
    btn.classList.add('active');
    const lbl = btn.querySelector('.pais-btn-label');
    if(lbl) lbl.style.display = 'inline';
  }

  // ── Indicador de país activo (bandera + nombre) ──────
  const elNombre = document.getElementById('pais-nombre');
  const elBandera = document.getElementById('pais-bandera');
  if(elNombre) elNombre.textContent = cfg.nombre;
  if(elBandera) elBandera.textContent = cfg.flag;

  // ── Moneda ───────────────────────────────────────────
  ['moneda-label','moneda-flete'].forEach(id=>{
    const el = document.getElementById(id);
    if(el) el.textContent = cfg.moneda;
  });

  // ── Config guardada o defaults ───────────────────────
  const saved = JSON.parse(localStorage.getItem('litper_pais_cfg_'+codigo) || 'null');
  const elDev   = document.getElementById('costo-dev');
  const elFlete = document.getElementById('costo-flete');
  if(elDev)   elDev.value   = saved?.costo_dev   ?? cfg.costo_dev;
  if(elFlete) elFlete.value = saved?.costo_flete ?? cfg.costo_flete;

  // ── Restaurar datos de este país ─────────────────────
  C.length=0; T.length=0; A.length=0; P.length=0;
  (PAIS_DATA[codigo].C||[]).forEach(x=>C.push(x));
  (PAIS_DATA[codigo].T||[]).forEach(x=>T.push(x));
  (PAIS_DATA[codigo].A||[]).forEach(x=>A.push(x));
  (PAIS_DATA[codigo].P||[]).forEach(x=>P.push(x));
  if(typeof G !== 'undefined' && PAIS_DATA[codigo].G){
    Object.keys(G).forEach(k=>delete G[k]);
    Object.assign(G, PAIS_DATA[codigo].G);
  }

  // ── Archivos badge ───────────────────────────────────
  const nFiles = parseInt(localStorage.getItem('litper_files_'+codigo) || '0');
  updateFilesBadge(nFiles);

  // ── Refrescar toda la UI ─────────────────────────────
  popSelects(); rMetrics(); rSem(); rCiu(); rAlertas(); rBloq();

  // ── Toast de confirmación ────────────────────────────
  showToast(cfg.flag + ' ' + cfg.nombre + ' · ' + cfg.moneda, 'info');
}


