// ─── MULTI-ARCHIVO: combina varios Excel en una sola carga ─────
// Procesa todos los archivos y acumula los datos
async function handleFiles(fileList){
  if(!fileList || fileList.length === 0) return;
  const files = Array.from(fileList);

  if(files.length === 1){
    // Un solo archivo — flujo normal
    return handleFile({ target: { files: [files[0]] }});
  }

  // Múltiples archivos — mostrar progreso
  const prog = document.createElement('div');
  prog.id = 'upload-progress';
  prog.style.cssText = 'position:fixed;bottom:80px;right:20px;z-index:9000;background:rgba(0,0,0,.9);border:1px solid rgba(0,255,136,.3);border-radius:12px;padding:12px 18px;font-family:var(--mono);font-size:12px;color:rgba(0,255,136,.9);min-width:260px;';
  prog.innerHTML = `<div style="margin-bottom:6px;font-weight:600">Combinando ${files.length} archivos...</div><div id="prog-detail" style="color:rgba(255,255,255,.6);font-size:11px;"></div>`;
  document.body.appendChild(prog);

  const allRows = []; // Acumulador de todas las filas
  let headerSaved = null;
  let processedCount = 0;

  for(let i = 0; i < files.length; i++){
    const file = files[i];
    document.getElementById('prog-detail').textContent = `(${i+1}/${files.length}) ${file.name}`;
    try {
      const rows = await readExcelFile(file);
      if(!rows || rows.length < 2) continue;

      if(!headerSaved){
        headerSaved = rows[0];
        allRows.push(rows[0]); // header una sola vez
      }
      // Agregar filas de datos (sin el header)
      for(let j = 1; j < rows.length; j++){
        allRows.push(rows[j]);
      }
      processedCount++;
    } catch(err){
      console.warn(`Error en ${file.name}:`, err.message);
    }
  }

  document.body.removeChild(prog);

  if(allRows.length < 2){
    alert('No se pudo leer ningún archivo. Verifica que sean .xlsx válidos.');
    return;
  }

  // Procesar el dataset combinado
  const combinedName = `${processedCount} archivos combinados (${PAISES[PAIS_ACTIVO].nombre})`;
  parseXLS(allRows, combinedName);

  // Guardar conteo para el badge
  localStorage.setItem('litper_files_'+PAIS_ACTIVO, String(processedCount));
  updateFilesBadge(processedCount);
}

// Leer un Excel y devolver Promise<rows>
function readExcelFile(file){
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = ev => {
      try {
        const wb = XLSX.read(ev.target.result, { type:'array' });
        const rows = XLSX.utils.sheet_to_json(wb.Sheets[wb.SheetNames[0]], { header:1 });
        resolve(rows);
      } catch(err){ reject(err); }
    };
    reader.onerror = () => reject(new Error('Error leyendo ' + file.name));
    reader.readAsArrayBuffer(file);
  });
}

// Compatibilidad con el input onchange anterior
function handleFile(e){
  const files = e.target.files;
  if(!files || files.length === 0) return;
  handleFiles(files);
}
// ═══════════════════════════════════════════════════════════════
// PARSER UNIVERSAL — Detecta automáticamente el formato del Excel
// ═══════════════════════════════════════════════════════════════
// Formatos soportados:
//   1. DROPI RAW   — Una fila por pedido (ESTATUS, CIUDAD DESTINO, TRANSPORTADORA)
//   2. DROPI PIVOT — Reporte agrupado por ciudad/carrier
//   3. SHOPIFY     — Orders export (Shipping City, Financial Status, etc.)
//   4. CSV genérico— Autodetecta columnas por nombre
// ═══════════════════════════════════════════════════════════════

function parseXLS(rows,fname){
  if(!rows||rows.length<2){alert('Excel vacío o sin datos.');return;}

  // ── DETECCIÓN AUTOMÁTICA DEL FORMATO ────────────────────────
  const header0 = (rows[0]||[]).map(h=>String(h||'').toUpperCase().trim());

  // Palabras clave por plataforma
  const isDropiRaw   = header0.includes('ESTATUS') && header0.includes('CIUDAD DESTINO');
  const isShopify    = header0.includes('FINANCIAL STATUS') || header0.includes('SHIPPING CITY');
  const isDropiPivot = !isDropiRaw && !isShopify;

  if(isDropiRaw){
    parseDropiRaw(rows, header0);
  } else if(isShopify){
    parseShopify(rows, header0);
  } else {
    parseDropiPivot(rows);
  }
}

// ── 1. DROPI RAW (ordenes_YYYYMMDD_HHMMSS.xlsx) ─────────────────
// Una fila = un pedido. Columnas clave: ESTATUS, CIUDAD DESTINO, TRANSPORTADORA
function parseDropiRaw(rows, header){
  // Estados que cuentan como ENTREGADO
  const ENT_OK = new Set(['ENTREGADO','NOVEDAD SOLUCIONADA','ENTREGADA']);
  // Estados que cuentan como DEVOLUCION
  const ENT_DEV = new Set(['DEVOLUCION','DEVOLUCION EN TRANSITO','RECHAZADO','CANCELADO','DEVUELTO']);
  // En tránsito (se excluyen del denominador para tasa real)
  // Todo lo demás = en tránsito (EN REPARTO, GUIA_GENERADA, etc.)

  const iCiudad = header.indexOf('CIUDAD DESTINO');
  const iTrans  = header.indexOf('TRANSPORTADORA');
  const iStatus = header.indexOf('ESTATUS');
  const iValor  = header.indexOf('VALOR FACTURADO');
  // Fallbacks para otros CSV similares
  const iCiudad2 = iCiudad<0 ? header.findIndex(h=>h.includes('CIUDAD')) : iCiudad;
  const iTrans2  = iTrans<0  ? header.findIndex(h=>h.includes('TRANSPORT')||h.includes('CARRIER')) : iTrans;
  const iStatus2 = iStatus<0 ? header.findIndex(h=>h.includes('ESTADO')||h.includes('STATUS')||h.includes('ESTATUS')) : iStatus;

  const cMap={}, tMap={};
  let totalValor=0;

  for(let i=1;i<rows.length;i++){
    const r=rows[i];
    const ciudad = String(r[iCiudad2]||r[iCiudad]||'').trim().toUpperCase();
    const trans  = String(r[iTrans2] ||r[iTrans] ||'').trim().toUpperCase();
    const status = String(r[iStatus2]||r[iStatus]||'').trim().toUpperCase();
    const valor  = parseFloat(r[iValor]||0)||0;
    if(!ciudad||!status)continue;

    const esEnt = ENT_OK.has(status);
    const esDev = ENT_DEV.has(status);
    // Solo contamos finalizados para la tasa (excluye en tránsito)
    const esFin = esEnt||esDev;
    totalValor += valor;

    // Ciudad
    if(!cMap[ciudad]) cMap[ciudad]={n:ciudad,t:0,fin:0,e:0,d:0,c:{}};
    cMap[ciudad].t++;
    if(esFin) cMap[ciudad].fin++;
    if(esEnt) cMap[ciudad].e++;
    if(esDev) cMap[ciudad].d++;
    if(trans){ cMap[ciudad].c[trans]=(cMap[ciudad].c[trans]||0)+1; }

    // Transportadora
    if(trans && esFin){
      if(!tMap[trans]) tMap[trans]={transportadora:trans,total:0,entregados:0,devoluciones:0};
      tMap[trans].total++;
      if(esEnt) tMap[trans].entregados++;
      if(esDev) tMap[trans].devoluciones++;
    }
  }

  if(!Object.keys(cMap).length){alert('No se encontraron pedidos con ciudad y estado. Verifica el Excel.');return;}

  // Construir array C (formato interno: [ciudad, total, entregados, devoluciones, tasa, best, carriers])
  C=Object.values(cMap).map(v=>{
    const base = v.fin>0 ? v.fin : v.t; // usar finalizados si hay, si no total
    const te = Math.round(v.e/base*1000)/10;
    const carriers = Object.entries(v.c).map(([t,n])=>{
      const tData = tMap[t]||{};
      const tRate = tData.total>0 ? Math.round(tData.entregados/tData.total*1000)/10 : 0;
      return [t,n,Math.round(v.e*(n/v.t)),tRate];
    }).sort((a,b)=>b[1]-a[1]);
    const bt = carriers.filter(x=>x[1]>=5);
    const best = bt.length ? [bt.reduce((a,b)=>b[3]>a[3]?b:a)[0], bt.reduce((a,b)=>b[3]>a[3]?b:a)[3]] : null;
    return [v.n, v.t, v.e, v.d, te, best, carriers];
  }).sort((a,b)=>b[1]-a[1]);

  // Construir T (transportadoras)
  T.length=0;
  Object.values(tMap).map(t=>({
    ...t,
    tasa_entrega:Math.round(t.entregados/t.total*1000)/10,
    tasa_devolucion:Math.round(t.devoluciones/t.total*1000)/10
  })).sort((a,b)=>b.total-a.total).forEach(t=>T.push(t));

  _finalizarCarga(fname);
}

// ── 2. SHOPIFY EXPORT ────────────────────────────────────────────
function parseShopify(rows, header){
  // Shopify usa: Shipping City, Financial Status, Shipping Company (carrier)
  const iCiudad = header.findIndex(h=>h.includes('SHIPPING CITY')||h.includes('BILLING CITY'));
  const iStatus = header.findIndex(h=>h.includes('FINANCIAL STATUS')||h.includes('FULFILLMENT STATUS'));
  const iTrans  = header.findIndex(h=>h.includes('SHIPPING COMPANY')||h.includes('CARRIER'));
  const ENT_OK  = new Set(['PAID','FULFILLED','SHIPPED','DELIVERED']);
  const ENT_DEV = new Set(['REFUNDED','PARTIALLY REFUNDED','CANCELLED','VOID']);
  const cMap={}, tMap={};
  for(let i=1;i<rows.length;i++){
    const r=rows[i];
    const ciudad = String(r[iCiudad]||'').trim().toUpperCase();
    const status = String(r[iStatus]||'').trim().toUpperCase();
    const trans  = String(r[iTrans] ||'SHOPIFY').trim().toUpperCase();
    if(!ciudad||!status)continue;
    const esEnt=ENT_OK.has(status), esDev=ENT_DEV.has(status), esFin=esEnt||esDev;
    if(!cMap[ciudad]) cMap[ciudad]={n:ciudad,t:0,fin:0,e:0,d:0,c:{}};
    cMap[ciudad].t++;
    if(esFin)cMap[ciudad].fin++;
    if(esEnt)cMap[ciudad].e++;
    if(esDev)cMap[ciudad].d++;
    cMap[ciudad].c[trans]=(cMap[ciudad].c[trans]||0)+1;
    if(esFin){
      if(!tMap[trans])tMap[trans]={transportadora:trans,total:0,entregados:0,devoluciones:0};
      tMap[trans].total++;
      if(esEnt)tMap[trans].entregados++;
      if(esDev)tMap[trans].devoluciones++;
    }
  }
  C=Object.values(cMap).map(v=>{
    const base=v.fin>0?v.fin:v.t;
    const te=Math.round(v.e/base*1000)/10;
    const carriers=Object.entries(v.c).map(([t,n])=>[t,n,0,0]).sort((a,b)=>b[1]-a[1]);
    const best=carriers.length?[carriers[0][0],te]:null;
    return[v.n,v.t,v.e,v.d,te,best,carriers];
  }).sort((a,b)=>b[1]-a[1]);
  T.length=0;
  Object.values(tMap).map(t=>({...t,tasa_entrega:Math.round(t.entregados/t.total*1000)/10,tasa_devolucion:Math.round(t.devoluciones/t.total*1000)/10})).sort((a,b)=>b.total-a.total).forEach(t=>T.push(t));
  _finalizarCarga(fname);
}

// ── 3. DROPI PIVOT (formato reporte agrupado) ────────────────────
function parseDropiPivot(rows){
  const nC=[],ts=new Set();let cc=null;
  const cMap={};
  const KN=['COORDINADORA','INTERRAPIDISIMO','ENVIA','TCC','VELOCES','JAMV-DRIVE','FUTURA','DOMINA','SERVIENTREGA','DEPRISA','EFECTY'];
  for(let i=5;i<rows.length;i++){
    const r=rows[i];const lbl=r[0]?String(r[0]).trim():'';if(!lbl)continue;
    const isT=KN.some(t=>lbl.toUpperCase().includes(t));
    if(isT){
      const dev=parseFloat(r[1])||0,ent=parseFloat(r[3])||0,tot=parseFloat(r[5])||0;
      if(cc&&tot>0){
        ts.add(lbl);
        if(!cMap[cc])cMap[cc]={n:cc,t:0,e:0,d:0,c:[]};
        cMap[cc].t+=tot;cMap[cc].e+=ent;cMap[cc].d+=dev;
        cMap[cc].c.push([lbl,Math.round(tot),Math.round(ent),Math.round(ent/tot*1000)/10]);
      }
    }else if(!lbl.toUpperCase().includes('TOTAL')&&!lbl.toUpperCase().includes('GRAN'))cc=lbl;
  }
  if(!Object.keys(cMap).length){alert('No se encontraron datos. Verifica el formato del Excel (pivot).');return;}
  C=Object.values(cMap).map(v=>{
    v.c.sort((a,b)=>b[1]-a[1]);
    const te=Math.round(v.e/v.t*1000)/10;
    const bt=v.c.filter(x=>x[1]>=10);
    const best=bt.length?[bt.reduce((a,b)=>b[3]>a[3]?b:a)[0],bt.reduce((a,b)=>b[3]>a[3]?b:a)[3]]:null;
    return[v.n,v.t,v.e,v.d,te,best,v.c];
  }).sort((a,b)=>b[1]-a[1]);
  const tm={};
  C.forEach(c=>c[6].forEach(r=>{if(!tm[r[0]])tm[r[0]]={transportadora:r[0],total:0,entregados:0,devoluciones:0};tm[r[0]].total+=r[1];tm[r[0]].entregados+=r[2];tm[r[0]].devoluciones+=r[1]-r[2];}));
  T.length=0;Object.values(tm).map(t=>({...t,tasa_entrega:Math.round(t.entregados/t.total*1000)/10,tasa_devolucion:Math.round((t.total-t.entregados)/t.total*1000)/10})).sort((a,b)=>b.total-a.total).forEach(t=>T.push(t));
  _finalizarCarga(fname);
}

// ── FUNCIÓN COMPARTIDA: finalizar carga y actualizar UI ──────────
function _finalizarCarga(fname){
  const totE=C.reduce((s,c)=>s+c[2],0), totA=C.reduce((s,c)=>s+c[1],0);
  const nT=new Set(C.flatMap(c=>c[6].map(x=>x[0]))).size;
  G={total:totA,entregados:totE,devoluciones:totA-totE,
     tasa_entrega:Math.round(totE/totA*1000)/10,
     ciudades:C.length,transportadoras:T.length||nT};
  // Alertas
  A.length=0;
  C.forEach(c=>{
    const[n,tot,ent,dev,te,,cs]=c;
    if(tot>=100&&te<65)A.push([0,n,tot,te,'Alto volumen + tasa crítica de entrega']);
    else if(tot>=50&&te<70)A.push([1,n,tot,te,'Tasa de entrega por debajo del umbral']);
    const tr2=cs.filter(x=>x[1]>=20);
    if(tr2.length>=2){
      const rates=tr2.map(x=>x[3]||0).filter(r=>r>0);
      if(rates.length>=2){
        const diff=Math.max(...rates)-Math.min(...rates);
        if(diff>=15){
          const mj=tr2.reduce((a,b)=>(b[3]||0)>(a[3]||0)?b:a);
          const pr=tr2.reduce((a,b)=>(b[3]||0)<(a[3]||0)?b:a);
          A.push([2,n,tot,te,`Gap ${diff.toFixed(0)}% — ${pr[0]}(${(pr[3]||0)}%) → ${mj[0]}(${(mj[3]||0)}%)`]);
        }
      }
    }
  });
  A.sort((a,b)=>(a[0]-b[0])||b[2]-a[2]);
  // Pareto
  P.length=0;let acum=0;
  C.slice(0,60).forEach(c=>{acum+=c[1];P.push([c[0],c[1],c[4],Math.round(acum/totA*1000)/10]);});
  popSelects();rMetrics();rSem();rCiu();rAlertas();rBloq();
  const plat=fname&&fname.toLowerCase().includes('orden')?'Dropi RAW':fname&&fname.toLowerCase().includes('shopify')?'Shopify':'Excel';
  showToast(`${plat} cargado: ${C.length} ciudades · ${G.total.toLocaleString('es-CO')} pedidos · ${G.tasa_entrega}% entrega`, 'ok');
}
function _finalizarCarga(fname){
  const totE=C.reduce((s,c)=>s+c[2],0), totA=C.reduce((s,c)=>s+c[1],0);
  const nT=new Set(C.flatMap(c=>c[6].map(x=>x[0]))).size;
  G={total:totA,entregados:totE,devoluciones:totA-totE,
     tasa_entrega:Math.round(totE/totA*1000)/10,
     ciudades:C.length,transportadoras:T.length||nT};
  // Alertas
  A.length=0;
  C.forEach(c=>{
    const[n,tot,ent,dev,te,,cs]=c;
    if(tot>=100&&te<65)A.push([0,n,tot,te,'Alto volumen + tasa crítica de entrega']);
    else if(tot>=50&&te<70)A.push([1,n,tot,te,'Tasa de entrega por debajo del umbral']);
    const tr2=cs.filter(x=>x[1]>=20);
    if(tr2.length>=2){
      const rates=tr2.map(x=>x[3]||0).filter(r=>r>0);
      if(rates.length>=2){
        const diff=Math.max(...rates)-Math.min(...rates);
        if(diff>=15){
          const mj=tr2.reduce((a,b)=>(b[3]||0)>(a[3]||0)?b:a);
          const pr=tr2.reduce((a,b)=>(b[3]||0)<(a[3]||0)?b:a);
          A.push([2,n,tot,te,`Gap ${diff.toFixed(0)}% — ${pr[0]}(${(pr[3]||0)}%) → ${mj[0]}(${(mj[3]||0)}%)`]);
        }
      }
    }
  });
  A.sort((a,b)=>(a[0]-b[0])||b[2]-a[2]);
  // Pareto
  P.length=0;let acum=0;
  C.slice(0,60).forEach(c=>{acum+=c[1];P.push([c[0],c[1],c[4],Math.round(acum/totA*1000)/10]);});

  // ── DETECCIÓN DE CIUDADES NUEVAS ──────────────────────────────
  detectarCiudadesNuevas();

  // ── ACTUALIZAR BENCHMARK CROSS-SELLERS ───────────────────────
  actualizarBenchmark();

  popSelects();rMetrics();rSem();rCiu();rAlertas();rBloq();
  const plat=fname&&fname.toLowerCase().includes('orden')?'Dropi RAW':fname&&fname.toLowerCase().includes('shopify')?'Shopify':'Excel';
  showToast(`${plat} cargado: ${C.length} ciudades · ${G.total.toLocaleString('es-CO')} pedidos · ${G.tasa_entrega}% entrega`, 'ok');

  // ── PERSISTIR EN SUPABASE (async, no bloquea UI) ──────────────
  (async function(){
    try {
      const uploadData = {
        filename: fname || 'upload',
        total_orders: G.total,
        delivered: G.entregados,
        returned: G.devoluciones,
        delivery_rate: G.tasa_entrega,
        cities_count: G.ciudades,
        carriers_count: G.transportadoras
      };
      const upload = await saveUpload(uploadData);
      if(upload && upload.id){
        await Promise.all([
          saveCityStats(upload.id, C),
          saveCarrierStats(upload.id, T)
        ]);
        
      }
    } catch(e){ console.warn('Supabase upload save failed (offline?):', e); }
  })();
}

// ═══════════════════════════════════════════════════════════
// 1. DETECCIÓN DE CIUDADES NUEVAS
// Compara las ciudades del upload con las del historial
// guardado en localStorage. Muestra banner si hay nuevas.
// ═══════════════════════════════════════════════════════════
function detectarCiudadesNuevas(){
  const KEY = 'litper_ciudades_historico_' + PAIS_ACTIVO;
  let historico;
  try{ historico = JSON.parse(localStorage.getItem(KEY)) || []; }
  catch(e){ historico = []; }

  const actuales   = C.map(c=>c[0]);
  const setHistoric = new Set(historico);
  const nuevas     = actuales.filter(c => !setHistoric.has(c));

  // Guardar el historial actualizado
  const merged = Array.from(new Set([...historico, ...actuales]));
  try{ localStorage.setItem(KEY, JSON.stringify(merged)); }catch(e){}

  // Si hay ciudades nuevas → banner
  if(nuevas.length > 0){
    mostrarBannerCiudadesNuevas(nuevas);
  }
}

function mostrarBannerCiudadesNuevas(ciudades){
  // Remover banner anterior si existe
  const old = document.getElementById('banner-ciudades-nuevas');
  if(old) old.remove();

  const banner = document.createElement('div');
  banner.id = 'banner-ciudades-nuevas';
  banner.style.cssText = `
    position:fixed;top:56px;left:0;right:0;z-index:8000;
    background:linear-gradient(135deg,rgba(0,255,136,.12),rgba(168,85,247,.08));
    border-bottom:1px solid rgba(0,255,136,.3);
    padding:10px 18px;display:flex;align-items:center;gap:12px;
    backdrop-filter:blur(12px);animation:fadeDown .4s ease-out;
  `;

  const preview = ciudades.slice(0, 5).join(', ') + (ciudades.length > 5 ? ` y ${ciudades.length - 5} más` : '');

  banner.innerHTML = `
    <span style="font-size:16px">📍</span>
    <div style="flex:1;min-width:0">
      <div style="font-size:13px;font-weight:600;color:rgba(0,255,136,.95)">
        ${ciudades.length} ciudad${ciudades.length > 1 ? 'es nuevas detectadas' : ' nueva detectada'} — ${PAISES[PAIS_ACTIVO].flag} ${PAISES[PAIS_ACTIVO].nombre}
      </div>
      <div style="font-size:11px;color:rgba(255,255,255,.55);margin-top:2px;font-family:var(--mono)">
        ${preview}
      </div>
    </div>
    <button onclick="mostrarConfigCiudadesNuevas(${JSON.stringify(ciudades).replace(/"/g,'&quot;')})"
      style="background:rgba(0,255,136,.15);border:1px solid rgba(0,255,136,.3);border-radius:8px;padding:5px 12px;font-size:11px;font-weight:600;color:rgba(0,255,136,.9);cursor:pointer;white-space:nowrap;font-family:var(--mono)">
      ⚙️ Configurar carrier
    </button>
    <button onclick="this.closest('#banner-ciudades-nuevas').remove()"
      style="background:transparent;border:none;color:rgba(255,255,255,.4);font-size:16px;cursor:pointer;padding:0 4px;line-height:1">✕</button>
  `;

  document.body.insertBefore(banner, document.body.children[0]);
  // Auto-cerrar en 12 segundos
  setTimeout(() => { if(document.getElementById('banner-ciudades-nuevas')) banner.remove(); }, 12000);
}

function mostrarConfigCiudadesNuevas(ciudades){
  document.getElementById('banner-ciudades-nuevas')?.remove();
  // Abrir modal de configuración de carriers por ciudad
  const overlay = document.createElement('div');
  overlay.style.cssText = 'position:fixed;inset:0;z-index:9000;background:rgba(0,0,0,.7);display:flex;align-items:center;justify-content:center;padding:20px;';

  const modal = document.createElement('div');
  modal.style.cssText = 'background:#0d0f1a;border:1px solid rgba(0,255,136,.25);border-radius:16px;padding:24px;max-width:520px;width:100%;max-height:80vh;overflow-y:auto;';

  const carriers_disponibles = [...new Set(T.map(t=>t.transportadora))].filter(Boolean);

  let rows_html = ciudades.slice(0,15).map(ciudad => {
    const cityData = C.find(c=>c[0]===ciudad);
    const options_html = carriers_disponibles.map(c => `<option value="${c}">${c}</option>`).join('');
    return `
      <div style="display:grid;grid-template-columns:1fr 150px;gap:8px;align-items:center;padding:8px 0;border-bottom:1px solid var(--b1)">
        <div>
          <div style="font-size:12px;font-weight:600;color:rgba(255,255,255,.85)">${ciudad}</div>
          <div style="font-size:10px;color:rgba(255,255,255,.35);font-family:var(--mono)">${cityData ? cityData[1]+' pedidos' : 'nueva'}</div>
        </div>
        <select data-ciudad="${ciudad}"
          style="background:rgba(255,255,255,.06);border:1px solid rgba(255,255,255,.15);border-radius:8px;padding:5px 8px;font-size:11px;color:rgba(255,255,255,.8);font-family:var(--mono);cursor:pointer">
          <option value="">-- Sin asignar --</option>
          ${options_html}
        </select>
      </div>`;
  }).join('');

  if(ciudades.length > 15) rows_html += `<div style="font-size:11px;color:rgba(255,255,255,.35);text-align:center;padding:8px;font-family:var(--mono)">+${ciudades.length-15} ciudades más...</div>`;

  modal.innerHTML = `
    <div style="display:flex;align-items:center;gap:10px;margin-bottom:18px">
      <span style="font-size:18px">📍</span>
      <div>
        <div style="font-size:14px;font-weight:600;color:rgba(0,255,136,.95)">Configurar carrier para ciudades nuevas</div>
        <div style="font-size:11px;color:rgba(255,255,255,.45);margin-top:2px">${ciudades.length} ciudades nuevas en ${PAISES[PAIS_ACTIVO].flag} ${PAISES[PAIS_ACTIVO].nombre}</div>
      </div>
    </div>
    ${rows_html}
    <div style="display:flex;gap:8px;margin-top:16px">
      <button onclick="guardarConfigNuevasCiudades(this)"
        style="flex:1;background:linear-gradient(135deg,rgba(0,255,136,.9),rgba(168,85,247,.8));border:none;border-radius:10px;padding:10px;font-size:12px;font-weight:700;color:#000;cursor:pointer">
        GUARDAR CONFIGURACIÓN
      </button>
      <button onclick="this.closest('[style*=inset]').remove()"
        style="background:rgba(255,255,255,.06);border:1px solid rgba(255,255,255,.15);border-radius:10px;padding:10px 16px;font-size:12px;color:rgba(255,255,255,.6);cursor:pointer">
        Ahora no
      </button>
    </div>
  `;

  overlay.appendChild(modal);
  overlay.onclick = e => { if(e.target===overlay) overlay.remove(); };
  document.body.appendChild(overlay);
}

function guardarConfigNuevasCiudades(btn){
  const modal = btn.closest('[style*="border-radius:16px"]');
  const selects = modal.querySelectorAll('select[data-ciudad]');
  const config = {};
  selects.forEach(s => { if(s.value) config[s.dataset.ciudad] = s.value; });

  const KEY = 'litper_carrier_config_' + PAIS_ACTIVO;
  let existing = {};
  try{ existing = JSON.parse(localStorage.getItem(KEY)) || {}; }catch(e){}
  Object.assign(existing, config);
  try{ localStorage.setItem(KEY, JSON.stringify(existing)); }catch(e){}

  btn.closest('[style*=inset]').remove();
  const saved = Object.keys(config).length;
  if(saved > 0){
    const t = document.createElement('div');
    t.style.cssText = 'position:fixed;bottom:80px;right:20px;z-index:9999;background:rgba(0,230,118,.9);color:#000;padding:10px 16px;border-radius:10px;font-size:12px;font-weight:600;';
    t.textContent = `✅ ${saved} carriers configurados`;
    document.body.appendChild(t);
    setTimeout(()=>t.remove(), 3000);
  }
}

