// ── RIPPLE EFFECT (Material Design) ──────────────────────────────
document.addEventListener('click', function(e) {
  const btn = e.target.closest('.btn-up, .btnai, .btn-inst, .pag button');
  if (!btn) return;
  const rect = btn.getBoundingClientRect();
  const size = Math.max(rect.width, rect.height);
  const ripple = document.createElement('span');
  ripple.className = 'ripple-circle';
  ripple.style.cssText = `width:${size}px;height:${size}px;left:${e.clientX-rect.left-size/2}px;top:${e.clientY-rect.top-size/2}px`;
  btn.appendChild(ripple);
  setTimeout(() => ripple.remove(), 600);
});

// ── MOUSE POSITION para btn-up glow ──────────────────────────────
document.querySelectorAll('.btn-up, .btnai').forEach(btn => {
  btn.addEventListener('mousemove', e => {
    const r = btn.getBoundingClientRect();
    btn.style.setProperty('--mx', ((e.clientX - r.left) / r.width * 100) + '%');
    btn.style.setProperty('--my', ((e.clientY - r.top) / r.height * 100) + '%');
  });
});

// ── STAGGER ALERT ITEMS ───────────────────────────────────────────
function animateAlerts() {
  document.querySelectorAll('.aitem').forEach((el, i) => {
    el.style.animation = 'none';
    el.offsetHeight; // reflow
    el.style.animation = `alertSlide .3s ${i * 0.06}s var(--ease-out) both`;
  });
}

// ── TAB SWITCH CON ANIMACIÓN ──────────────────────────────────────
const origSwitch = switchTab;
window.switchTab = function(name) {
  origSwitch(name);
  if (name === 'alertas') setTimeout(animateAlerts, 100);
  // Re-apply ripple listeners después de render
  setTimeout(() => {
    document.querySelectorAll('.btn-up, .btnai, .btn-inst').forEach(btn => {
      btn.addEventListener('mousemove', e => {
        const r = btn.getBoundingClientRect();
        btn.style.setProperty('--mx', ((e.clientX - r.left) / r.width * 100) + '%');
        btn.style.setProperty('--my', ((e.clientY - r.top) / r.height * 100) + '%');
      });
    });
  }, 50);
};

