// ════════════════════════════════════════════
// SECTION 2: AI MODEL COMPARISON
// Compare 3 models in parallel
// ════════════════════════════════════════════
// ════════════════════════════════════════════════════════════
// FEATURE 1: COMPARAR 3 MODELOS EN PARALELO
// ════════════════════════════════════════════════════════════
async function compareModels(){
  const btn = document.getElementById('btn-compare');
  const zone = document.getElementById('compare-zone');
  const sp = document.getElementById('compare-sp');
  const prompt = buildPrompt(activeAI);
  
  // Mostrar zona + reset cards
  zone.style.display = 'block';
  sp.style.display = 'inline-block';
  btn.disabled = true;
  zone.scrollIntoView({behavior:'smooth', block:'nearest'});

  const models = ['claude','chatgpt','gemini'];
  models.forEach(m => {
    document.getElementById('cc-'+m).className = 'compare-body loading';
    document.getElementById('cs-'+m).textContent = '⏳ Procesando...';
    document.getElementById('cc-'+m).textContent = 'Conectando vía servidor...';
  });

  // Llamar cada modelo vía API proxy
  async function callModel(model){
    try{
      const text = await callAIProxy(model, prompt, 900);
      return {text, model};
    }catch(e){return{error:e.message,model};}
  }

  const promises = models.map(m => callModel(m));
  
  // Actualizar UI al completarse cada promesa (racing)
  promises.forEach((p,i) => {
    const m = models[i];
    p.then(result => {
      const card = document.getElementById('cc-'+m);
      const status = document.getElementById('cs-'+m);
      if(result.error){
        card.className = 'compare-body loading';
        card.textContent = '✗ '+result.error;
        status.textContent = '❌ Error';
        status.style.color = 'var(--error)';
      }else{
        card.className = 'compare-body';
        card.textContent = result.text;
        status.textContent = '✅ Listo';
        status.style.color = 'var(--gn)';
        // Guardar en historial
        saveToHistory(m, result.text);
        // Persistir en Supabase
        saveAIAnalysis({ model: m, type: 'compare', prompt: prompt.slice(0,500), response: result.text.slice(0,2000) }).catch(()=>{});
      }
    });
  });
  
  // Esperar todas para quitar spinner
  Promise.allSettled(promises).then(() => {
    btn.disabled = false;
    sp.style.display = 'none';
  });
}

