// FEATURE 3: HISTORIAL (últimos 10 análisis en localStorage)
// ════════════════════════════════════════════════════════════

const HIST_KEY = 'litper_ai_history';
const HIST_MAX = 10;

const ANALYSIS_LABELS = {gen:'📊 Análisis general',rojo:'🔴 Ciudades en rojo',swap:'🔄 Carrier swap',escalar:'🚀 Escalar',plan:'📋 Plan semanal'};
const MODEL_COLORS = {claude:'rgba(245,158,11,.2)',chatgpt:'rgba(16,185,129,.2)',gemini:'rgba(129,140,248,.2)'};
const MODEL_TEXT = {claude:'#f59e0b',chatgpt:'#10b981',gemini:'#818cf8'};

function saveToHistory(model, text){
  try{
    const hist = JSON.parse(localStorage.getItem(HIST_KEY)||'[]');
    const entry = {
      id: Date.now(),
      model: model||currentModel||'claude',
      type: activeAI||'gen',
      label: ANALYSIS_LABELS[activeAI]||'Análisis',
      date: new Date().toLocaleString('es-CO',{dateStyle:'short',timeStyle:'short'}),
      text: text,
      preview: text.substring(0,120)+'...'
    };
    hist.unshift(entry);
    if(hist.length > HIST_MAX) hist.splice(HIST_MAX);
    localStorage.setItem(HIST_KEY, JSON.stringify(hist));
    updateHistCount();
  }catch(e){}
}

function loadHistory(){
  try{ return JSON.parse(localStorage.getItem(HIST_KEY)||'[]'); }
  catch(e){ return []; }
}

function updateHistCount(){
  const n = loadHistory().length;
  const el = document.getElementById('hist-count');
  if(el) el.textContent = n;
}

function toggleHistory(){
  const panel = document.getElementById('hist-panel');
  panel.classList.toggle('show');
  if(panel.classList.contains('show')) renderHistory();
}

function renderHistory(){
  const hist = loadHistory();
  const list = document.getElementById('hist-list');
  if(!hist.length){
    list.innerHTML='<div class="hist-empty">Sin análisis guardados aún.<br>Los últimos '+HIST_MAX+' análisis aparecerán aquí.</div>';
    return;
  }
  list.innerHTML = hist.map((h,i) => `
    <div class="hist-item" onclick="loadFromHistory(${i})" title="Clic para cargar este análisis">
      <div class="hist-item-top">
        <span class="hist-model" style="background:${MODEL_COLORS[h.model]||'rgba(255,255,255,.1)'};color:${MODEL_TEXT[h.model]||'#fff'}">${(h.model||'IA').toUpperCase()}</span>
        <span class="hist-type">${h.label||'Análisis'}</span>
        <span class="hist-date">${h.date}</span>
      </div>
      <div class="hist-preview">${h.preview||''}</div>
    </div>
  `).join('');
}

function loadFromHistory(idx){
  const hist = loadHistory();
  if(!hist[idx]) return;
  const entry = hist[idx];
  const out = document.getElementById('ai-out');
  out.className = 'aiout';
  out.textContent = entry.text;
  showActions(entry.text);
  document.getElementById('hist-panel').classList.remove('show');
  // Scroll to result
  out.scrollIntoView({behavior:'smooth',block:'nearest'});
}

function clearHistory(){
  if(!confirm('¿Limpiar todo el historial de análisis?')) return;
  localStorage.removeItem(HIST_KEY);
  updateHistCount();
  renderHistory();
}

// ════════════════════════════════════════════════════════════
// FEATURE 4: MODO VOZ (Web Speech API)
// ════════════════════════════════════════════════════════════

let speechSynth = window.speechSynthesis;
let currentUtterance = null;
let isSpeaking = false;

function toggleVoice(){
  if(!speechSynth){
    alert('Tu navegador no soporta síntesis de voz. Prueba con Chrome.');
    return;
  }
  if(isSpeaking){
    stopVoice();
    return;
  }
  const text = document.getElementById('ai-out').textContent;
  if(!text||text.length<10||text.startsWith('⚠️')){
    alert('Primero genera un análisis para escuchar.');
    return;
  }
  // Limpiar emojis y caracteres especiales para mejor TTS
  const cleanText = text
    .split('').filter(function(ch){var code=ch.codePointAt(0);return code<0x2000;}).join('')
    .replace(/\n{2,}/g,' ').replace(/\n/g,' ')
    .substring(0,3000); // Límite de 3000 chars para no colapsar TTS
  
  currentUtterance = new SpeechSynthesisUtterance(cleanText);
  currentUtterance.lang = 'es-CO';
  currentUtterance.rate = 0.95;
  currentUtterance.pitch = 1.0;
  currentUtterance.volume = 1.0;
  
  // Buscar voz en español
  const voices = speechSynth.getVoices();
  const esVoice = voices.find(v=>v.lang.startsWith('es')&&v.name.includes('Google')) 
    || voices.find(v=>v.lang.startsWith('es')) 
    || null;
  if(esVoice) currentUtterance.voice = esVoice;
  
  currentUtterance.onstart = ()=>{
    isSpeaking = true;
    const btn = document.getElementById('btn-speak');
    btn.classList.add('speaking');
    btn.innerHTML = '<span class="voice-icon">⏹</span> <span>Detener</span>';
    document.getElementById('speak-label').textContent = 'Detener';
  };
  currentUtterance.onend = ()=>{ isSpeaking=false; resetVoiceBtn(); };
  currentUtterance.onerror = ()=>{ isSpeaking=false; resetVoiceBtn(); };
  
  speechSynth.speak(currentUtterance);
}

function stopVoice(){
  if(speechSynth) speechSynth.cancel();
  isSpeaking = false;
  resetVoiceBtn();
}

function resetVoiceBtn(){
  const btn = document.getElementById('btn-speak');
  if(!btn) return;
  btn.classList.remove('speaking');
  btn.innerHTML = '<span class="voice-icon">🔊</span> <span id="speak-label">Escuchar</span>';
}

// Cargar voces (Chrome las carga async)
if(speechSynth && speechSynth.onvoiceschanged !== undefined){
  speechSynth.onvoiceschanged = ()=>speechSynth.getVoices();
}

