// PATCH: Interceptar runAI para mostrar acciones + guardar historial
// ════════════════════════════════════════════════════════════
const _origRunAI = window.runAI || function(){};
// Monkey-patch: después de runAI, mostrar acciones
// Lo hacemos via MutationObserver en ai-out
(function(){
  const aiOut = document.getElementById('ai-out');
  if(!aiOut) return;
  const obs = new MutationObserver(()=>{
    const txt = aiOut.textContent;
    if(txt && txt.length > 50 && !aiOut.classList.contains('loading')){
      showActions(txt);
      saveToHistory(currentModel||'claude', txt);
    }
  });
  obs.observe(aiOut, {childList:true, characterData:true, subtree:true});
})();

