function exportBloqueoCSV(){
  if(!C||C.length===0){alert('Primero carga datos.');return;}
  const umbral = parseFloat(document.getElementById('umbral-slider')?.value||70);
  const bloqueadas = C.filter(x=>x[4]<umbral&&x[1]>=10);
  if(bloqueadas.length===0){alert('No hay ciudades por debajo del umbral actual ('+umbral+'%).');return;}
  const now = new Date().toLocaleDateString('es-CO').replace(/\//g,'-');
  let csv = `LISTA DE BLOQUEO — Umbral ${umbral}% — ${now}
Ciudad,Tasa_%,Total_Pedidos,Carrier_Actual,Accion_Recomendada
`;
  bloqueadas.forEach(row=>{
    const mc = Array.isArray(row[5])?row[5][0]:(row[5]||'N/A');
    const accion = row[4]<60?'BLOQUEAR_INMEDIATO':'REDUCIR_VOLUMEN';
    csv += `"${row[0]}",${row[4]},${row[1]},"${mc}","${accion}"
`;
  });
  downloadFile(csv, `LitperPro_Bloqueo_${umbral}pct_${now}.csv`, 'text/csv');
}

// ════════════════════════════════════════════════════════════
// IMPORTAR — CSV y JSON
// ════════════════════════════════════════════════════════════

function triggerCSVImport(){ document.getElementById('fi-csv').click(); }
function importFromJSON(){ document.getElementById('fi-json-imp').click(); }

function handleCSVImport(input){
  const file = input.files?.[0];
  if(!file) return;
  const reader = new FileReader();
  reader.onload = function(e){
    try{
      const text = e.target.result;
      const lines = text.trim().split('\n').filter(l=>l.trim());
      if(lines.length < 2){ alert('CSV vacío o formato incorrecto.'); return; }
      
      // Detectar header y columnas
      const header = lines[0].toLowerCase().split(',').map(h=>h.trim().replace(/"/g,''));
      const colCiudad = header.findIndex(h=>h.includes('ciudad')||h.includes('city'));
      const colCarrier = header.findIndex(h=>h.includes('carrier')||h.includes('transport'));
      const colEstado = header.findIndex(h=>h.includes('estado')||h.includes('status')||h.includes('entrega'));
      
      if(colCiudad<0||colCarrier<0){
        alert('No se detectaron columnas de ciudad y carrier.\n\nColumnas encontradas: '+header.join(', ')+'\n\nAsegúrate de que el CSV tenga columnas: Ciudad, Transportadora, Estado');
        return;
      }
      
      // Simular estructura similar al Excel
      const rows = [];
      for(let i=1;i<lines.length;i++){
        const cols = lines[i].split(',').map(c=>c.trim().replace(/"/g,''));
        rows.push({
          ciudad: cols[colCiudad]||'',
          carrier: cols[colCarrier]||'',
          estado: cols[colEstado]||'Entregado'
        });
      }
      
      // Procesar agrupando igual que el Excel
      const cityMap = {};
      rows.forEach(r=>{
        if(!r.ciudad) return;
        const k = r.ciudad.toUpperCase().trim();
        if(!cityMap[k]) cityMap[k] = {total:0, ent:0};
        cityMap[k].total++;
        const esEntrega = r.estado.toLowerCase().includes('entre')||r.estado.toLowerCase().includes('success')||r.estado==='1'||r.estado==='true';
        if(esEntrega) cityMap[k].ent++;
      });
      
      // Reconstruir C (estructura simplificada sin breakdown por carrier)
      C = Object.entries(cityMap)
        .map(([k,v])=>[k,v.total,v.ent,v.total-v.ent,Math.round(v.ent/v.total*1000)/10,null,[]])
        .sort((a,b)=>b[1]-a[1]);
      
      const totalP = Object.values(cityMap).reduce((s,v)=>s+v.total,0);
      const totalE = Object.values(cityMap).reduce((s,v)=>s+v.ent,0);
      G = {total:totalP,entregados:totalE,devoluciones:totalP-totalE,tasa_entrega:Math.round(totalE/totalP*1000)/10,ciudades:C.length,transportadoras:1};
      
      showExpToast('✅ CSV importado: '+C.length+' ciudades · '+totalP.toLocaleString('es-CO')+' pedidos');
      rMetrics(); // Actualizar métricas en pantalla
      switchTab('semaforo'); // Ir al semáforo
    }catch(err){
      alert('Error procesando CSV: '+err.message);
    }
  };
  reader.readAsText(file, 'UTF-8');
  input.value = '';
}

function handleJSONImport(input){
  const file = input.files?.[0];
  if(!file) return;
  const reader = new FileReader();
  reader.onload = function(e){
    try{
      const data = JSON.parse(e.target.result);
      if(!data.global||!data.ciudades){
        alert('JSON inválido. Debe ser un archivo exportado desde LitperPro (contiene: global, ciudades, carriers, alertas).');
        return;
      }
      // Restaurar datos
      G = data.global;
      C = data.ciudades.map(d=>[d.ciudad,d.total,d.entregados,d.devoluciones,d.tasa,d.mejorCarrier,d.breakdown||[]]);
      if(data.carriers) T = data.carriers;
      if(data.alertas) A = data.alertas;
      
      showExpToast('✅ JSON restaurado: '+C.length+' ciudades · Exportado: '+(data.exportado||'desconocido').substring(0,10));
      rMetrics();
      switchTab('semaforo');
    }catch(err){
      alert('Error leyendo JSON: '+err.message+'\n\nAsegúrate de que sea un archivo exportado por LitperPro.');
    }
  };
  reader.readAsText(file, 'UTF-8');
  input.value = '';
}

// Patch switchTab para manejar panel expImp
document.addEventListener('DOMContentLoaded', function(){
  const origST = window.switchTab;
  if(!origST) return;
  window.switchTab = function(name){
    const expPanel = document.getElementById('panel-expImp');
    if(name === 'expImp'){
      document.querySelectorAll('.panel').forEach(p=>{p.classList.remove('active');p.style.display='';});
      document.querySelectorAll('.tab').forEach(t=>t.classList.remove('active'));
      if(expPanel){ expPanel.style.display='block'; expPanel.classList.add('active'); }
      document.querySelectorAll('.tab').forEach(t=>{ if(t.textContent.includes('Export')||t.textContent.includes('Import')) t.classList.add('active'); });
    }else{
      if(expPanel){ expPanel.style.display='none'; expPanel.classList.remove('active'); }
      origST(name);
    }
  };
});

