function lpAddMsg(role, text, isTyping){
  var msgs = document.getElementById('lp-msgs');
  var div = document.createElement('div');
  div.className = 'lp-msg ' + role;
  if(isTyping) div.id = 'lp-typing';

  var av = document.createElement('div');
  av.className = 'lp-av ' + (role==='bot'?'bot':'user');
  av.textContent = role==='bot' ? '✦' : '👤';

  var bubble = document.createElement('div');
  bubble.className = 'lp-bubble ' + (role==='bot'?'bot':'user');

  if(isTyping){
    bubble.className += ' typing';
    bubble.innerHTML = '<div class="lp-dot"></div><div class="lp-dot"></div><div class="lp-dot"></div>';
  }else{
    bubble.style.whiteSpace = 'pre-wrap';
    bubble.textContent = text;
    // Acciones en mensajes del bot
    if(role==='bot' && text.length > 30){
      var actRow = document.createElement('div');
      actRow.className = 'lp-msg-actions';
      actRow.innerHTML = '<button class="lp-msg-act" onclick="lpCopyMsg(this)" title="Copiar">📋 Copiar</button>' +
        '<button class="lp-msg-act" onclick="lpSpeakMsg(this)" title="Escuchar">🔊</button>';
      div.appendChild(av); div.appendChild(bubble); div.appendChild(actRow);
      msgs.appendChild(div);
      msgs.scrollTop = msgs.scrollHeight;
      lpSaveHistory(role, text);
      lpUpdateReportBar();
      return;
    }
  }

  div.appendChild(av);
  div.appendChild(bubble);
  msgs.appendChild(div);
  msgs.scrollTop = msgs.scrollHeight;
  if(!isTyping){
    lpSaveHistory(role, text);
    lpUpdateReportBar();
  }
}

