// ── LLAMADA A LA API (vía servidor) ──────────────────────────
async function lpCallAPI(directPrompt, userMsg){
  // Check AI quota
  try {
    var q = await checkAIQuota();
    if(!q.allowed){
      lpAddMsg('bot', '⚠️ Límite de consultas IA alcanzado ('+q.used+'/'+q.quota+'). Actualiza tu plan en /pricing para continuar.');
      return;
    }
  } catch(e){}

  lpTyping = true;
  document.getElementById('lp-send').disabled = true;
  lpAddMsg('bot', '', true);

  try{
    var sysPrompt = lpBuildSystemPrompt();
    var chatMsgs = lpHistory.slice(-10).map(function(m){return {role:m.role,content:m.content};});
    if(directPrompt) chatMsgs.push({role:'user',content:directPrompt});
    var txt = await callChatProxy(lpChatModel, chatMsgs, sysPrompt, 700);

    lpRemoveTyping();
    lpAddMsg('bot', txt);
    lpHistory.push({role:'assistant',content:txt,ts:Date.now()});
    if(lpHistory.length>40) lpHistory.splice(0,2);
    lpSaveHistoryChatDB();
    incrementAIUsage().catch(function(){});

  }catch(e){
    lpRemoveTyping();
    var msg = '✗ Error: ' + e.message;
    if(e.message.indexOf('Sesion expirada')>=0) msg += '\n\n→ Recarga la pagina para iniciar sesion de nuevo.';
    else if(e.message.indexOf('no configurada')>=0) msg += '\n\n→ Contacta al administrador para configurar las API keys en Vercel.';
    else if(e.message.indexOf('Timeout')>=0) msg += '\n\n→ La IA esta saturada. Intenta de nuevo en unos segundos.';
    else msg += '\n\n→ Las API keys se configuran en Vercel > Settings > Environment Variables.';
    lpAddMsg('bot', msg);
  }finally{
    lpTyping = false;
    document.getElementById('lp-send').disabled = false;
  }
}

// ── HISTORIAL LOCAL ───────────────────────────────────────────
var LP_HIST_DB = 'litper_chat_sessions';

var _currentChatSessionId = null;
function lpSaveHistoryChatDB(){
  try{
    var sessions = JSON.parse(localStorage.getItem(LP_HIST_DB)||'[]');
    var session = {
      id: Date.now(),
      model: lpChatModel,
      date: new Date().toLocaleString('es-CO',{dateStyle:'short',timeStyle:'short'}),
      preview: lpHistory.length>0 ? (lpHistory[lpHistory.length-1].content||'').substring(0,80) : '',
      messages: lpHistory.slice(-20)
    };
    sessions.unshift(session);
    if(sessions.length>15) sessions.splice(15);
    localStorage.setItem(LP_HIST_DB, JSON.stringify(sessions));
    lpRenderHistSidebar();
  }catch(e){}
  // Persist to Supabase
  saveChatSession({
    id: _currentChatSessionId,
    model: lpChatModel,
    title: lpHistory.length>0 ? (lpHistory[0].content||'Chat').substring(0,100) : 'Chat',
    messages: lpHistory.slice(-30),
    msg_count: lpHistory.length
  }).then(function(data){ if(data && data.id) _currentChatSessionId = data.id; }).catch(function(){});
}

function lpRenderHistSidebar(){
  var list = document.getElementById('lp-hist-list');
  if(!list) return;
  var sessions = [];
  try{ sessions = JSON.parse(localStorage.getItem(LP_HIST_DB)||'[]'); }catch(e){}
  if(!sessions.length){
    list.innerHTML='<div style="font-size:11px;color:var(--t3);text-align:center;padding:16px">Sin conversaciones guardadas</div>';
    return;
  }
  list.innerHTML = sessions.slice(0,8).map(function(s,i){
    return '<div class="lp-hist-item" onclick="lpLoadSession('+i+')" title="Cargar conversación">' +
      '<div class="lp-hist-time">' + s.date + ' · ' + (s.model||'IA').toUpperCase() + '</div>' +
      '<div class="lp-hist-prev">' + (s.preview||'...') + '</div></div>';
  }).join('');
}

function lpLoadSession(idx){
  var sessions = [];
  try{ sessions = JSON.parse(localStorage.getItem(LP_HIST_DB)||'[]'); }catch(e){}
  var s = sessions[idx];
  if(!s) return;
  lpHistory = s.messages||[];
  // Renderizar mensajes
  var msgs = document.getElementById('lp-msgs');
  msgs.innerHTML = '';
  lpHistory.forEach(function(m){
    var role = m.role==='assistant'?'bot':m.role;
    lpAddMsg(role, m.content);
  });
  lpUpdateReportBar();
}

// ── REPORT BAR ───────────────────────────────────────────────
function lpUpdateReportBar(){
  var bar = document.getElementById('lp-report-bar');
  var label = document.getElementById('lp-rep-label');
  var count = document.getElementById('lp-msgs').querySelectorAll('.lp-msg').length;
  if(bar) bar.classList.toggle('show', count>1);
  if(label) label.textContent = count + ' mensajes · ' + lpChatModel.toUpperCase();
}

// ── ACCIONES DE MENSAJE ───────────────────────────────────────
function lpCopyMsg(btn){
  var bubble = btn.closest('.lp-msg').querySelector('.lp-bubble');
  if(!bubble) return;
  navigator.clipboard.writeText(bubble.textContent).then(function(){
    btn.textContent='✅ Copiado';
    setTimeout(function(){btn.innerHTML='📋 Copiar';},2000);
  });
}

function lpSpeakMsg(btn){
  var bubble = btn.closest('.lp-msg').querySelector('.lp-bubble');
  if(!bubble) return;
  lpSpeakText(bubble.textContent);
}

// ── EXPORT / REPORTE ─────────────────────────────────────────
function lpGetChatText(){
  var msgs = document.getElementById('lp-msgs').querySelectorAll('.lp-msg');
  var lines = [];
  msgs.forEach(function(m){
    var role = m.classList.contains('user') ? 'YO' : 'LITPERBOT';
    var bubble = m.querySelector('.lp-bubble');
    if(bubble && !bubble.classList.contains('typing')){
      lines.push('[' + role + ']\n' + bubble.textContent + '\n');
    }
  });
  return lines.join('\n');
}

function lpCopyChat(){
  var text = lpGetChatText();
  navigator.clipboard.writeText(text).then(function(){
    lpShowToast('✅ Chat copiado al portapapeles');
  }).catch(function(){ lpShowToast('✗ No se pudo copiar'); });
}

function lpExportTxt(){
  var text = lpGetChatText();
  var now = new Date().toLocaleDateString('es-CO').replace(/\//g,'-');
  var header = 'LITPERBOT — Sesión de chat\nFecha: '+new Date().toLocaleString('es-CO',{dateStyle:'full',timeStyle:'short'})+'\nModelo: '+lpChatModel.toUpperCase()+'\n'+'='.repeat(50)+'\n\n';
  var blob = new Blob([header+text],{type:'text/plain;charset=utf-8'});
  var a=document.createElement('a');a.href=URL.createObjectURL(blob);a.download='LitperBot_Chat_'+now+'.txt';a.click();URL.revokeObjectURL(a.href);
  lpShowToast('💾 Chat exportado');
}

function lpExportNotion(){
  var text = lpGetChatText();
  var date = new Date().toLocaleString('es-CO',{dateStyle:'short',timeStyle:'short'});
  var notion = '## LitperBot — Sesión ' + date + '\n> Modelo: ' + lpChatModel.toUpperCase() + '\n\n---\n\n' + text;
  navigator.clipboard.writeText(notion).then(function(){
    lpShowToast('📓 Copiado con formato Notion');
  });
}

function lpGenerateReport(){
  // Generar reporte ejecutivo como análisis especial
  var hasData = typeof C!=='undefined' && C && C.length>0;
  if(!hasData){ lpShowToast('⚠️ Primero carga un Excel de datos'); return; }
  lpAddMsg('user','📄 Generar reporte ejecutivo completo');
  var reportPrompt = 'Genera un reporte ejecutivo completo de las operaciones logísticas de Litper. Incluye:\n1. Resumen ejecutivo (3-4 líneas)\n2. Métricas clave con números exactos\n3. Top 5 ciudades críticas con acción inmediata\n4. Top 5 ciudades para escalar (oportunidades)\n5. Análisis de carriers (ranking y CPA estimado)\n6. Plan de acción para los próximos 7 días (equipo logística y marketing)\n7. KPI objetivo para el lunes siguiente\nFormato: estructurado, listo para compartir con el equipo.';
  lpCallAPI(reportPrompt);
}

// ── VOZ ───────────────────────────────────────────────────────
function lpSpeakText(text){
  if(!window.speechSynthesis) return;
  var clean = text.split('').filter(function(ch){var cp=ch.codePointAt(0);return cp<0x1F300;}).join('').replace(/\n{2,}/g,' ').replace(/\n/g,' ').substring(0,3000);
  lpStopVoice();
  lpCurrentSpeech = new SpeechSynthesisUtterance(clean);
  lpCurrentSpeech.lang='es-CO';lpCurrentSpeech.rate=0.95;lpCurrentSpeech.pitch=1;
  var voices=speechSynthesis.getVoices();
  var v=voices.find(function(vv){return vv.lang.startsWith('es')&&vv.name.includes('Google');})||voices.find(function(vv){return vv.lang.startsWith('es');})||null;
  if(v) lpCurrentSpeech.voice=v;
  lpCurrentSpeech.onend=lpStopVoice;
  lpCurrentSpeech.onerror=lpStopVoice;
  speechSynthesis.speak(lpCurrentSpeech);
  lpSpeaking=true;
  var btn=document.getElementById('lp-voice-btn');
  if(btn){btn.innerHTML='⏹ Detener';btn.style.color='var(--error)';}
}

function lpToggleVoice(){
  if(lpSpeaking){lpStopVoice();return;}
  // Leer el último mensaje del bot
  var bubbles=document.getElementById('lp-msgs').querySelectorAll('.lp-bubble.bot:not(.typing)');
  if(!bubbles.length){lpShowToast('No hay mensajes para escuchar');return;}
  lpSpeakText(bubbles[bubbles.length-1].textContent);
}

function lpStopVoice(){
  if(window.speechSynthesis) speechSynthesis.cancel();
  lpSpeaking=false;lpCurrentSpeech=null;
  var btn=document.getElementById('lp-voice-btn');
  if(btn){btn.innerHTML='🔊 Escuchar';btn.style.color='';}
}

// ── GUARDAR EN HISTORIAL ──────────────────────────────────────
function lpSaveHistory(role, text){
  lpHistory.push({role:role==='bot'?'assistant':role, content:text, ts:Date.now()});
  if(lpHistory.length>60) lpHistory.splice(0,2);
}

// ── TOAST ────────────────────────────────────────────────────
function lpShowToast(msg){
  var t=document.getElementById('lp-toast');
  if(!t){t=document.createElement('div');t.id='lp-toast';document.body.appendChild(t);}
  t.textContent=msg; t.classList.add('show');
  clearTimeout(t._t); t._t=setTimeout(function(){t.classList.remove('show');},3000);
}

// ── INIT ─────────────────────────────────────────────────────
(function lpInit(){
  // Cargar historial del sidebar
  setTimeout(lpRenderHistSidebar, 800);
  // Responsive: en mobile usar float
  if(window.innerWidth<600) lpChatMode='float';
})();


// ════════════════════════════════════════════
// SECTION 5: ONBOARDING WIZARD
// First-run setup flow
// ════════════════════════════════════════════
// ── ONBOARDING WIZARD LOGIC ─────────────────────────────────
var _onbFile = null;
(async function checkOnboarding(){
  try {
    var profile = await getProfile();
    if(!profile) return;
    if(profile.onboarding_completed) return;
    // Show onboarding
    document.getElementById('onb-overlay').style.display = 'flex';
    // Pre-fill store name if org has one
    if(profile.organizations && profile.organizations.name){
      document.getElementById('onb-store').value = profile.organizations.name;
    }
  } catch(e){ console.warn('Onboarding check:', e); }
})();

function onbNext(step){
  // Save step 1 data
  if(step === 1){
    var storeName = document.getElementById('onb-store').value.trim();
    if(storeName){
      updateProfile({ store_name: storeName }).catch(function(){});
      // Also update org name
      (async function(){
        var orgId = await getOrgId();
        if(orgId){
          supabase.from('organizations').update({ name: storeName }).eq('id', orgId).then(function(){});
        }
      })();
    }
  }
  // Handle file from step 2
  if(step === 2 && _onbFile){
    // Trigger the main upload handler
    var mainInput = document.getElementById('fi');
    if(mainInput){
      var dt = new DataTransfer();
      dt.items.add(_onbFile);
      mainInput.files = dt.files;
      mainInput.dispatchEvent(new Event('change', {bubbles:true}));
    }
  }
  // Navigate
  var next = step + 1;
  if(next > 3) return onbFinish();
  for(var i=1;i<=3;i++){
    document.getElementById('onb-s'+i).classList.toggle('active', i===next);
    var dot = document.getElementById('onb-d'+i);
    dot.classList.remove('active','done');
    if(i < next) dot.classList.add('done');
    else if(i === next) dot.classList.add('active');
  }
}

function onbHandleFile(file){
  if(!file) return;
  _onbFile = file;
  var zone = document.getElementById('onb-drop');
  zone.innerHTML = '<div class="onb-upload-icon">✅</div><div class="onb-upload-text" style="color:var(--cn);font-weight:600">'+file.name+'</div><div class="onb-upload-hint">'+Math.round(file.size/1024)+'KB · Listo para analizar</div>';
  var btn = document.getElementById('onb-upload-btn');
  btn.disabled = false;
  btn.style.opacity = '1';
}

async function onbFinish(){
  document.getElementById('onb-overlay').style.display = 'none';
  try { await updateProfile({ onboarding_completed: true }); } catch(e){}
}

function onbSkip(){
  onbFinish();
}
